from gen import validate
v=validate()
def stay(g,r,c):
    H=len(g); W=len(g[0])
    def get(i,j): return g[i][j] if 0<=i<H and 0<=j<W else 0
    belowEmpty = get(r+1,c-1)==0 and get(r+1,c)==0 and get(r+1,c+1)==0
    clamp = get(r,c-1)==0 and get(r,c+1)==0 and get(r+1,c)!=0
    return belowEmpty or clamp
def p(g):
    H=len(g);W=len(g[0]); out=[[0]*W for _ in range(H)]
    for r in range(H):
        for c in range(W):
            if g[r][c]:
                if stay(g,r,c): out[r][c]=g[r][c]
                elif c+1<W: out[r][c+1]=g[r][c]
    return out
ex=v['train'][1]
def show(g):
  for row in g:print(' '.join(map(str,row)))
print('GOT');show(p(ex['input']))
print('EXP');show(ex['output'])
